import{_ as b,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"异想体书页——历史层","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/异想体书页/异想体书页——历史层.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/异想体书页/异想体书页——历史层.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/异想体书页/异想体书页——历史层.md"};function d(o,p,_,l,i,c){return e(),a("div",null,[...p[0]||(p[0]=[r("h1",{id:"异想体书页——历史层",tabindex:"-1"},[t("异想体书页——历史层 "),r("a",{class:"header-anchor",href:"#异想体书页——历史层","aria-label":'Permalink to "异想体书页——历史层"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风027")])])],-1),n('<h1 id="异想体书页——历史层-1" tabindex="-1">异想体书页——历史层 <a class="header-anchor" href="#异想体书页——历史层-1" aria-label="Permalink to &quot;异想体书页——历史层&quot;">​</a></h1><p>异想体书页—历史层</p><p>该功能是图书馆馆长借助图书馆使司书与书中记录的异想体共鸣，初始不开启，直到轮回者通过第一个异想体的试炼为止<br> 通过记录在书中的异想体的试炼之后开放对应异想体书页的购买<br> 每提升一次情感等级，都可以选择一次异想体书页，不同异想体书页要求的负面/正面情感硬币数量不同<br> 以下的书页分为崩溃书页/觉醒书页，书页的选取有情感等级限制，只有到达对应情感等级才能选取<br> 异想体书页在选择后立即生效，效果持续一场景。同一书页不可重复选取。</p><p>焦化少女对应书页</p><p>余烬<br> D+500<br> 觉醒书页<br> 要求：无<br> 焦黑的身体象征着少女支离破碎的希望，永恒的火焰却寄托着对爱的强烈渴望。</p><p>应用该书页后，当前场景中，当你使用招架获得伤害抵消数时，你以下列骰子与敌人拼点：<br> 格挡骰：若成功，则你获得决心上的传奇属性*2点格挡防御，此外，下一轮使用第一张书页时，将一枚突刺骰：若拼点成功，则这次攻击额外对敌人施加1层烧伤置入书页末尾。<br> 这不会视作你使用了一张书页。</p><p>残光<br> D+500<br> 崩溃书页<br> 要求：负面情感硬币＞正面情感硬币<br> 她从不轻易表露内心的情感，就像一枚不知何时才会引爆的定时炸弹。</p><p>在影片开始时，随机选取一张你已经持有的书页，那张书页被标记为火柴书页，<br> 随后，当你在该影片中获得这张异想体书页时开始，每轮结束时，那张书页的所有骰子的上限增加1点，最高上升决心属性点，<br> 若当前书页的最大值已经达到10点或以上，那么你每次使用书页，进行一次rd10的机运骰，若出目低于5，则受到1点火焰严重伤害。</p><p>脚步<br> C+1000<br> 崩溃书页<br> 条件：负面情感硬币至少为3枚<br> 我来找你了，和我一起化成灰吧。</p><p>当你应用这张书页并且韧性下降到20%以下之后，<br> 当你与敌人使用书页拼点时，你的内在火焰将会同时把敌人和你自己燃尽，这会使你的这次攻击额外附加11点火焰严重伤害，并且施加3层烧伤，<br> 在这次攻击之后，你不可避免的死亡，在该影片不能复活。</p><p>快乐泰迪对应书页</p><p>思念的拥抱<br> D+500<br> 觉醒书页<br> 条件：正面情感硬币＞负面情感硬币<br> 泰迪正紧紧抱着某人。泰迪非常喜欢拥抱。但，似乎有些不对劲。</p><p>当你应用这张异想体书页之后，你每次拼点成功时，都会有50%的几率追加等同于骰子出目的混乱抗性伤害。</p><p>幸福的记忆<br> D+500<br> 觉醒书页<br> 条件：正面情感硬币＞负面情感硬币，且正面情感硬币至少为3枚<br> 可泰迪再也不想失去它的主人了。</p><p>影片开始时，标记你已持有的一个书页，在你应用这张书页之后，你每次使用那张书页使其减少2点能耗（最低到1），<br> 如果其已经将能耗减低至1，那么改为获得在使用那张书页时的2DP决心检定上的增强加值，每以此法获得3点DP就会有1点DP不生效。</p><p>表达爱意<br> D+1000<br> 崩溃书页<br> 条件：负面情感硬币＞正面情感硬币，且负面情感硬币数量至少为3<br> 它的记忆始于温暖的怀抱。</p><p>应用该书页时，你需要消耗1点意志力才能使这张书页正常生效，你使用的书页的所有拼点骰子最大值+2，但是如果你在某次拼点中所有骰子均获得胜利，<br> 那么下一张书页的所有拼点骰子的最大值-2。</p><p>精灵盛宴对应书页</p><p>精灵的呵护<br> D+500<br> 崩溃书页<br> 条件：负面情感硬币＞正面情感硬币<br> 精灵会保护职员们。在她们的悉心照料下，一切都会变得安宁祥和。</p><p>应用该书页时，你需要消耗1点意志力才能使这张书页正常生效，自你应用该书页开始，你在该场景中获得快速医疗3（医疗点36），<br> 但是如果你在同一轮中被击中次数超过3次，那么在本轮结束时受到完好上限*25%的不可避免的严重伤害，随后结束该效果</p><p>贪食<br> C+1000<br> 觉醒书页<br> 条件：正面情感硬币＞负面情感硬币<br> 说到底，这些精灵不过是一群爱吃肉的怪物罢了，所谓的“呵护”也仅仅是为了保持食物的新鲜。</p><p>在应用这张书页开始，当你在本回合中击中已经被击中过的敌人时，你的攻击视作具有【吸血5】，并且额外造成1—3点力场严重伤害（在攻击命中时投掷rd3，根据结果追加伤害）。</p><p>猎食<br> C+1000<br> 觉醒书页<br> 条件：负面情感硬币＞正面情感硬币<br> 他的内脏和眼球遭到不明生物啃食，受损严重。此外，我们察觉到精灵们的嘴角沾有某人的血肉。</p><p>每回合开始时对当前场景除自身外的所有队友造成1点不可避免的严重伤害，并且获得持续一轮的3层强壮和4层迅捷。<br> 在回合结束时恢复3点完好（医疗点36）。</p><p>【强壮】：攻击检定上获得1点附加成功。<br> 【迅捷】：先攻上获得2点加值。</p><p>蜂后对应书页</p><p>孢子<br> C+1000<br> 觉醒书页<br> 条件：无<br> 研究表明，孢子内含有能在宿主体内孵化的蜂卵。</p><p>在应用该书页后，在本场景内，当你被攻击命中时，对攻击者造成3点火焰严重伤害，并且额外施加1层不可豁免的流血异常点数。</p><p>工蜂<br> C+1000<br> 崩溃书页<br> 条件：负面情感硬币＞正面情感硬币<br> 工蜂只表现出两种行为模式: 为蜂后提供营养素，扩大蜂群数量。</p><p>在应用该书页后，在本场景内，当你对上一轮对你造成伤害最高的敌人发动攻击时，对方以反射豁免对抗你的出目，若失败，则将其标记为‘威胁’，<br> 当未应用该书页的单位以挥砍/突刺/钝击伤害击中‘威胁’时，额外追加rd7点对应种类的严重伤害。</p><p>忠诚<br> B+2000<br> 崩溃书页<br> 条件：负面情感硬币＞正面情感硬币<br> 蜜蜂的忠诚是一种自然本能，一旦找到激发这种本能的方法，那么许多事物都将改变。</p><p>在应用该书页后，你在当前场景中，每受到3点严重伤害，就会为以你为中心，55M为半径的圆形范围内的全部队友提供1层强壮，每轮最多提供15点。</p><p>【强壮】：攻击检定上获得1点附加成功。</p><p>白雪公主的苹果对应书页</p><p>绞杀藤<br> C+1500<br> 觉醒书页<br> 条件：正面情感硬币＞负面情感硬币<br> 了无生机的藤蔓从苹果中蔓生而出，纵使全数干枯，也从未停止生长。</p><p>应用该书页之后，在当前场景中，<br> 每一轮开始时，你上一轮击中的最后一名需要以一个反射豁免对抗你上一轮攻击的出目，<br> 若其失败，则被施加6层束缚，并且当你使用突刺骰子与其拼点时，突刺骰子的上限增加2点。</p><p>【束缚】：先攻下降2点。</p><p>毒刺屏障<br> B+2000<br> 觉醒书页<br> 条件：正面情感硬币＞负面情感硬币<br> 被白雪公主咬过一口便遗弃在烂泥中的苹果，永远得不到幸福。那颗苹果在孤独与憎恶之中，日复一日地等待着腐烂……</p><p>使用该书页后，当你被攻击命中后，你对其造成2—8点突刺严重伤害，并且使其受到1~17层束缚，<br> 若你一次造成3层束缚，那么你回复等同于造成的突刺严重伤害点完好（144医疗点）</p><p>【束缚】：先攻下降2点。</p><p>恶意<br> B+2000<br> 觉醒书页<br> 条件：无<br> 伴随那与生俱来的恶意，花朵绽放之时，所有生命都将消亡。</p><p>在应用该书页的下一轮中，你以一个标准动作对敏感范围一半的圆形范围内的全部敌人进行一次攻击检定，<br> 这次攻击额外附带目标已损失完好*1点突刺严重伤害（最高30点）。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',44)])])}const D=b(s,[["render",d]]);export{f as __pageData,D as default};
